function scrollToActivePageBelowHeader() {
  setTimeout(() => {
    const header = document.querySelector("header");
    const activePage = document.querySelector(".page.active");

    if (!activePage) return;

    const headerHeight = header ? header.offsetHeight : 0;

    const finalTop = Math.max(
      activePage.offsetTop - headerHeight - 12,
      0
    );

    window.scrollTo({
      top: finalTop,
      behavior: "smooth"
    });

    console.log("Scrolled below header:", {
      activePage: activePage.id,
      headerHeight,
      finalTop,
      scrollY: window.scrollY
    });
  }, 350);
}

window.scrollToActivePageBelowHeader = scrollToActivePageBelowHeader;

async function showPage(id) {
  const launchHiddenPages = [
    "englishLessonJourney",
    "prosodyLab",
    "prosody",
    "arabicProsody",
    "prosodySection"
  ];

  if (launchHiddenPages.includes(id)) {
    alert("هذا القسم قيد التطوير وسيعود قريبًا بإصدار أقوى.");
    id = "home";
  }

  document.querySelectorAll(".page").forEach(page => {
    page.classList.remove("active");
    page.style.display = "none";
  });

  let target = document.getElementById(id);

  if (!target) {
    console.log("Page not found:", id);
    return;
  }

  target.classList.add("active");
  target.style.display = "block";

  try {
    localStorage.setItem("jakLastActivePage", id);
  } catch (error) {
    console.warn("Could not save last active page:", error);
  }

  if (id !== "examSolver") {
    const retryControls = document.getElementById("retryPracticeControls");
    if (retryControls) retryControls.remove();
  }

  // Premium gate for AI Center
  if (id === "aiCenter" && typeof isCurrentUserPremium === "function") {
    storePremiumGateOriginalContent("aiCenter");

    const allowed = await isCurrentUserPremium();

    if (!allowed && typeof renderPremiumLockedMessage === "function") {
      renderPremiumLockedMessage(target, "AI Center");
    }

    if (allowed && typeof restorePremiumGateOriginalContent === "function") {
      restorePremiumGateOriginalContent("aiCenter");
    }
  }

  if (id === "studentExams" && typeof loadStudentExams === "function") {
    loadStudentExams();
  }

  if (id === "leaderboard" && typeof loadLeaderboard === "function") {
    loadLeaderboard();
  }

  if (id === "premium" && typeof renderPaymentInfo === "function") {
    renderPaymentInfo();
  }

  if (id === "premium" && typeof protectPremiumAdminTools === "function") {
    protectPremiumAdminTools();
  }

  // English Lesson Journey safe init
  // Temporarily disabled for launch because englishLessonJourney is hidden above.
  if (id === "englishLessonJourney" && typeof initEnglishLessonJourney === "function") {
    initEnglishLessonJourney();
  }

  setTimeout(() => {
    target.scrollIntoView({
      behavior: "smooth",
      block: "start"
    });
  }, 100);
if (typeof hideProsodyLaunchElements === "function") {
  setTimeout(hideProsodyLaunchElements, 100);
}
if (id === "home" && typeof hideHomeLoginCTAIfLoggedIn === "function") {
  setTimeout(hideHomeLoginCTAIfLoggedIn, 150);
}
if (id === "planner" && typeof renderPlannerCommandCenterV2 === "function") {
  setTimeout(renderPlannerCommandCenterV2, 150);
}
if (id === "planner" && typeof organizePlannerForLaunch === "function") {
  setTimeout(organizePlannerForLaunch, 250);
}
if (id === "planner" && typeof setupPlannerStudyOSTabs === "function") {
  setTimeout(setupPlannerStudyOSTabs, 350);
}
  console.log("Showing page:", id);
}

