  async function getOrCreateBankSourceExam(meta, user) {
    const bankTitle = `Question Bank Source - ${meta.subject} Grade ${meta.grade_level} ${meta.unit}`;

    const existing = await client
      .from("exams")
      .select("*")
      .eq("teacher_id", user.id)
      .eq("title", bankTitle)
      .limit(1);

    if (existing.error) {
      throw existing.error;
    }

    if (existing.data && existing.data.length > 0) {
      return existing.data[0];
    }

    const examData = {
      title: bankTitle,
      description: "Internal source exam for Question Bank imported questions",
      time_limit: 10,
      question_count: 0,
      exam_type: "multiple_choice",
      subject: meta.subject,
      grade_level: meta.grade_level,
      unit: meta.unit,
      status: "draft",
      teacher_id: user.id
    };

    const created = await client
      .from("exams")
      .insert([examData])
      .select()
      .single();

    if (created.error) {
      throw created.error;
    }

    return created.data;
  }

