function goldenFormatContent(rawText) {
  const text = String(rawText || "");

  let safe = text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");

  // Bold: **text**
  safe = safe.replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>");

  // Underline: __text__
  safe = safe.replace(/__(.*?)__/g, "<u>$1</u>");

  // Highlight: ==text==
  safe = safe.replace(/==(.*?)==/g, '<mark class="golden-highlight">$1</mark>');

  // Color: [color:red]text[/color]
  safe = safe.replace(
    /\[color:(#[0-9a-fA-F]{3,6}|red|blue|green|orange|purple|black|gray|grey|brown)\](.*?)\[\/color\]/g,
    '<span style="color:$1;">$2</span>'
  );

  // Simple markdown tables
  const lines = safe.split("\n");
  let html = "";
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    if (
      line.trim().startsWith("|") &&
      lines[i + 1] &&
      /^\s*\|?[\s\-:|]+\|?\s*$/.test(lines[i + 1])
    ) {
      const headers = line
        .split("|")
        .map(x => x.trim())
        .filter(Boolean);

      i += 2;

      const rows = [];
      while (i < lines.length && lines[i].trim().startsWith("|")) {
        rows.push(
          lines[i]
            .split("|")
            .map(x => x.trim())
            .filter(Boolean)
        );
        i++;
      }

      html += `<table class="golden-content-table"><thead><tr>`;
      html += headers.map(h => `<th>${h}</th>`).join("");
      html += `</tr></thead><tbody>`;
      html += rows
        .map(row => `<tr>${row.map(cell => `<td>${cell}</td>`).join("")}</tr>`)
        .join("");
      html += `</tbody></table>`;
    } else {
      if (line.trim() === "") {
        html += "<br>";
      } else {
        html += `<p>${line}</p>`;
      }
      i++;
    }
  }

  return html;
}

window.goldenFormatContent = goldenFormatContent;
